pub fn help_text(topic: &str) -> Option<String> {
    let topic = topic.trim();
    if topic.is_empty() {
        return Some(crate::lang::commands::metadata::help_index());
    }
    if let Some(help) = crate::lang::commands::metadata::command_help(topic) {
        return Some(help.to_string());
    }
    legacy_help_text(topic).map(str::to_string)
}

fn legacy_help_text(topic: &str) -> Option<&'static str> {
    let h = match topic {
        "ols" | "reg" | "regress" => concat!(
            "ols(formula, df [, options])\n",
            "  Aliases: reg, regress\n\n",
            "  Options:\n",
            "    cov=nonrobust|HC1|HC2|HC3|HC4|robust   (default: nonrobust)\n",
            "    cluster=var       Cluster-robust SEs (one-way)\n",
            "    cluster2=var      Two-way clustering\n",
            "    nw=lags           Newey-West HAC\n\n",
            "  Example:\n",
            "    let m = ols(Y ~ X1 + X2, df)\n",
            "    let m = ols(Y ~ X1 + X2, df, cluster=firm)\n",
            "    print(m)\n",
        ),
        "test" => concat!(
            "test(model, ...)\n\n",
            "  Diagnostics:\n",
            "    test(m, \"white\")    White heteroskedasticity\n",
            "    test(m, \"bp\")       Breusch-Pagan\n",
            "    test(m, \"dw\")       Durbin-Watson\n\n",
            "  Wald / F-test:\n",
            "    test(m, \"X1\")              H0: beta_X1 = 0\n",
            "    test(m, \"X1\", \"X2\")       H0: beta_X1 = beta_X2 = 0 (joint)\n",
            "    test(m, \"X1 = X2\")         H0: beta_X1 = beta_X2\n",
            "    test(m, \"X1 = 0.5\")        H0: beta_X1 = 0.5\n",
        ),
        "nlcom" => concat!(
            "nlcom(model, expr)\n",
            "  Nonlinear combination of coefficients (delta method).\n\n",
            "  Example:\n",
            "    nlcom(m, X1 / X2)         Ratio of coefficients\n",
            "    nlcom(m, exp(_cons))       Exponentiate intercept\n",
        ),
        "margins" => concat!(
            "margins(model [, dydx=[vars], at_var=val])\n",
            "  Average Marginal Effects for logit/probit/poisson/negbin.\n\n",
            "  Options:\n",
            "    dydx=[X1, X2]     Show only selected variables\n",
            "    at_X1=0.5         Fix X1 at 0.5\n\n",
            "  Example:\n",
            "    margins(m_logit)\n",
            "    margins(m_logit, dydx=[age], at_educ=12)\n",
        ),
        "bootstrap" | "boot" | "bootse" => concat!(
            "bootstrap(estimator, formula, df, n=1000)\n",
            "  Generic bootstrap — works with any estimator.\n\n",
            "  Example:\n",
            "    bootstrap(ols, Y ~ X1 + X2, df, n=500)\n",
            "    bootstrap(logit, Y ~ X1, df, n=1000, alpha=0.10)\n",
        ),
        "esttab" => concat!(
            "esttab(m1, m2, ... [, fmt=txt|latex, path=\"file\"])\n",
            "  Model comparison table (with R-sq, Adj.R-sq, N).\n\n",
            "  Example:\n",
            "    esttab(m1, m2, m3)\n",
            "    esttab(m1, m2, fmt=latex, path=\"table.tex\")\n",
        ),
        "eststo" | "est_store" => "eststo(model)\n  Store a model for later esttab().\n\n  eststo(m1)\n  eststo(m2)\n  esttab()\n",
        "estclear" => "estclear()\n  Clear all models stored by eststo().\n\n  estclear()\n",
        "testparm" => "testparm(model, [\"x1\", \"x2\", ...])\n  Joint F-test that selected coefficients are all zero.\n  Supports OLS/WLS models.\n\n  testparm(m, [\"X1\", \"X2\"])\n",
        "fe" => concat!(
            "fe(formula, df [, id=col])\n",
            "  Fixed Effects (within estimator).\n",
            "  If xtset(df, id, time) declared, id= is optional.\n\n",
            "  Example:\n",
            "    xtset(df, firm, year)\n",
            "    let m = fe(Y ~ X1 + X2, df)\n",
        ),
        "re" => concat!(
            "re(formula, df [, id=col])\n",
            "  Random Effects (GLS).\n",
            "  If xtset(df, id, time) declared, id= is optional.\n",
        ),
        "xtset" => concat!(
            "xtset(df, id_col, time_col)\n",
            "  Declare panel structure. After xtset, panel estimators\n",
            "  (fe, re, ab, etc.) don't need id=/time=.\n\n",
            "  Example:\n",
            "    xtset(df, firm, year)\n",
            "    let m = fe(Y ~ X1 + X2, df)\n",
        ),
        "cluster" => concat!(
            "Cluster-robust standard errors\n\n",
            "  ols(Y ~ X, df, cluster=firm)\n",
            "  ols(Y ~ X, df, cluster=firm, cluster2=year)   two-way\n",
            "  ols(Y ~ X, df, nw=4)                          Newey-West\n",
            "  ols(Y ~ X, df, cov=robust)                    HC1\n",
        ),
        "winsor" | "winsorize" => concat!(
            "winsor(df, var, p=0.01 [, gen=new])\n",
            "  Winsorize at percentiles p and 1-p.\n\n",
            "  Example:\n",
            "    winsor(df, ret, p=0.05)             in-place\n",
            "    winsor(df, ret, p=0.01, gen=ret_w)  new column\n",
        ),
        "decode" => "decode(df, col, labels=[\"a\", \"b\", \"c\"])\n  Convert numeric column back to string using labels.\n  Opposite of encode().\n\n  decode(df, region_num, labels=[\"north\", \"south\", \"east\", \"west\"])\n",
        "encode" => concat!(
            "encode(df, col [, gen=new])\n",
            "  Convert string column to numeric (0, 1, 2...).\n\n",
            "  Example:\n",
            "    encode(df, region)                  in-place\n",
            "    encode(df, region, gen=region_num)  new column\n",
        ),
        "tabgen" | "xi" => concat!(
            "tabgen(df, var [, prefix=name])\n",
            "  Generate dummy variables from categorical.\n\n",
            "  Example:\n",
            "    tabgen(df, region)             // region_1, region_2, ...\n",
            "    tabgen(df, region, prefix=d)   // d_1, d_2, ...\n",
        ),
        "load" => concat!(
            "load \"path\" as alias [, opts...]\n",
            "  Load data into DataFrame.\n\n",
            "  Formats: CSV, TSV, JSON, DTA (Stata), Excel (xlsx/xls/ods), Parquet, SQLite, ODBC.\n",
            "  URLs are downloaded automatically.\n\n",
            "  Options:\n",
            "    sheet=Plan1       Excel sheet (default: first)\n",
            "    table=prices      SQLite/ODBC table\n",
            "    query=\"SELECT..\" Custom SQL query (SQLite/ODBC; incompatible com columns=/where=)\n",
            "    sep=\";\"           CSV delimiter (default: comma)\n",
            "    columns=[a,b,c]   Project only these columns (single string also accepted).\n",
            "                      Supported: Parquet (pushdown via Arrow), SQLite/ODBC\n",
            "                      (SELECT cols), CSV/TSV, DTA, Excel. Not yet for JSON.\n",
            "    where=\"pred\"      Row filter pushed down to the source when possible.\n",
            "                      Supported: Parquet (Arrow RowFilter + row group pruning\n",
            "                      by min/max statistics), SQLite/ODBC (WHERE),\n",
            "                      CSV/TSV, DTA, Excel. Not yet for JSON.\n",
            "                      Syntax (hayashi expression, column OP literal):\n",
            "                        ticker == \"AAPL\"\n",
            "                        price > 100 && volume > 1e6\n",
            "                        ticker in [\"AAPL\", \"MSFT\"]\n",
            "                        !(sector == \"Finance\")\n\n",
            "  Examples:\n",
            "    load \"data.csv\" as df\n",
            "    load \"data.tsv\" as df\n",
            "    load \"data.json\" as df\n",
            "    load \"panel.dta\" as panel\n",
            "    load \"sheet.xlsx\" as df, sheet=Data\n",
            "    load \"db.db\" as df, table=prices\n",
            "    load \"db.db\" as df, query=\"SELECT * FROM prices WHERE year > 2020\"\n",
            "    load \"odbc://DSN=mydb\" as df, query=\"SELECT * FROM returns\"\n",
            "    load \"cotacoes.parquet\" as aapl, columns=[ticker, date, adj_close],\n",
            "                                 where=\"ticker == \\\"AAPL\\\"\"\n",
            "    load \"db.db\" as df, table=prices, columns=[data, close], where=\"close > 100\"\n",
            "    load \"https://...data.csv\" as df\n\n",
            "  Temporal types (Timestamp, Date32, Date64) in Parquet are stored as\n",
            "  ISO 8601 strings (YYYY-MM-DD or YYYY-MM-DDTHH:MM:SS). Use\n",
            "  generate df ano = substr(date, 0, 4) to extract components, or\n",
            "  date(\"YYYY-MM-DD\") / datetime(\"YYYY-MM-DDTHH:MM:SS\") for a scalar\n",
            "  Unix timestamp.\n\n",
            "  ODBC requires: cargo build --features odbc + unixodbc installed.\n",
        ),
        "export" => concat!(
            "export(value, \"format\", \"path\")\n",
            "  Export DataFrame or results to file.\n\n",
            "  DataFrame: csv, json, tsv, xlsx, parquet, sqlite\n",
            "  OLS:       csv, latex, html\n",
            "  Models:    txt\n\n",
            "  Examples:\n",
            "    export(df, \"csv\", \"data.csv\")\n",
            "    export(df, \"xlsx\", \"data.xlsx\")\n",
            "    export(m, \"latex\", \"table.tex\")\n\n",
            "  Format can come from a variable:\n",
            "    let f = \"csv\"\n",
            "    export(df, f, \"data.csv\")\n",
        ),
        "generate" | "gen" => concat!(
            "generate df varname = expr\n",
            "  Create column in DataFrame. Supports arithmetic, functions,\n",
            "  comparisons (including strings: col == \"value\").\n\n",
            "  Example:\n",
            "    generate df lnY = log(Y)\n",
            "    generate df treat = (group == \"treated\")\n",
            "    generate df interact = X1 * X2\n",
        ),
        "replace" => "replace df varname = expr [if condition]\n  Overwrite column values in-place. Optional if-condition restricts rows.\n\n  replace df lnY = log(Y)\n  replace df treated = 1 if group == \"A\"\n",
        "wls" => "wls(formula, df, weights=\"col\")\n  Weighted Least Squares.\n  cov= option same as ols (HC1-HC4, robust, cluster, etc.).\n\n  let m = wls(Y ~ X1 + X2, df, weights=\"w\")\n",
        "iv" => concat!(
            "iv(endog_formula, instr_formula, df [, cov=...])\n",
            "  IV / 2SLS estimation.\n\n",
            "  Example:\n",
            "    let m = iv(Y ~ X1 + X_endog, ~ Z1 + Z2, df)\n",
        ),
        "logit" | "probit" => concat!(
            "logit(formula, df [, cov=...])\n",
            "probit(formula, df [, cov=...])\n\n",
            "  Example:\n",
            "    let m = logit(Y ~ X1 + X2, df)\n",
            "    margins(m)\n",
            "    predict df yhat = m, \"pr\"\n",
        ),
        "fmb" | "fama_macbeth" | "xtfmb" => concat!(
            "fmb(formula, df, time=col [, nw=lags])\n",
            "  Fama-MacBeth (1973): cross-sectional OLS per period.\n",
            "  SE = sigma(beta_t)/sqrt(T) (with optional Newey-West).\n\n",
            "  Options:\n",
            "    time=col    Time column (or via xtset)\n",
            "    nw=3        Newey-West lags for autocorrelation in beta_t\n\n",
            "  Example:\n",
            "    fmb(ret ~ beta + size + bm, df, time=month)\n",
            "    fmb(ret ~ beta + size, df, time=month, nw=4)\n",
        ),
        "coefplot" | "coef_plot" => concat!(
            "coefplot(model [, width=50])\n",
            "  ASCII coefficient plot with 95% CI.\n\n",
            "  Example:\n",
            "    let m = ols(Y ~ X1 + X2, df)\n",
            "    coefplot(m)\n",
        ),
        "predict" => concat!(
            "predict df varname = model [, \"kind\"]\n",
            "  kind: \"xb\" (default), \"residuals\", \"pr\", \"count\", \"yhat\"\n\n",
            "  Example:\n",
            "    predict df yhat = m_ols\n",
            "    predict df resid = m_ols, \"residuals\"\n",
            "    predict df prob = m_logit, \"pr\"\n",
        ),
        "list" => concat!(
            "list(df [, vars=[A,B], n=10])\n",
            "  Show observations from DataFrame.\n\n",
            "  Example:\n",
            "    list(df)\n",
            "    list(df, Y, X, 5)\n",
            "    list(df, vars=[Y, X], n=20)\n",
        ),
        "quietly" | "quiet" => concat!(
            "quietly(expr)\n",
            "  DEPRECATED. Use `quietly on` / `quietly off` instead.\n",
            "  This functional form still evaluates an expression without printing,\n",
            "  but will be removed in a future release.\n\n",
            "  Preferred:\n",
            "    quietly on\n",
            "    ols(Y ~ X, df)\n",
            "    quietly off\n\n",
            "  Deprecated:\n",
            "    quietly(ols(Y ~ X, df))\n",
            "    let m = quietly(ols(Y ~ X, df))\n",
        ),
        "capture" | "cap" => concat!(
            "capture(expr)\n",
            "  Evaluate expression ignoring errors.\n",
            "  Returns result on success, Nil on error.\n\n",
            "  Example:\n",
            "    capture(load \"maybe.csv\" as df)\n",
            "    capture(ols(Y ~ X, df))\n",
        ),
        "assert" => concat!(
            "assert(cond [, msg])\n",
            "  Error if condition is false.\n\n",
            "  Example:\n",
            "    assert(n > 0)\n",
            "    assert(n > 0, \"empty sample\")\n",
        ),
        "duplicates" => concat!(
            "duplicates(df, var [, action=report|drop|tag])\n",
            "  Report, remove, or tag duplicates.\n\n",
            "  Actions:\n",
            "    report (default) — count duplicates\n",
            "    drop  — remove duplicate rows\n",
            "    tag   — generate _dup column with count\n\n",
            "  Example:\n",
            "    duplicates(df, id)\n",
            "    duplicates(df, id, action=drop)\n",
        ),
        "date" => concat!(
            "date(\"YYYY-MM-DD\")\n",
            "  Parse date string to Unix timestamp (float).\n\n",
            "  let t = date(\"2024-06-15\")\n",
            "  let sub = filter(df, ts >= date(\"2020-01-01\"))\n",
        ),
        "datetime" => concat!(
            "datetime(\"YYYY-MM-DD HH:MM:SS\")\n",
            "  Parse datetime string to Unix timestamp (float).\n\n",
            "  let t = datetime(\"2024-06-15 14:30:00\")\n",
        ),
        "year" | "month" | "day" | "hour" | "minute" | "second" | "dow" => concat!(
            "year(col), month(col), day(col), hour(col), minute(col), second(col), dow(col)\n",
            "  Extract date/time component from a DateTime column or timestamp.\n",
            "  dow = day of week (0=Monday, 6=Sunday).\n\n",
            "  generate df Y = year(date_col)\n",
            "  generate df M = month(date_col)\n",
            "  generate df W = dow(date_col)\n",
        ),
        "format" | "fmt" => concat!(
            "format(value, fmt_str)\n",
            "  Format numeric value as string.\n\n",
            "  Example:\n",
            "    display format(3.14159, \"%.2f\")  // \"3.14\"\n",
            "    let s = format(gdp, \"%.0f\")\n",
        ),
        "label" => concat!(
            "label(df, var, \"description\")\n",
            "  Store label for a DataFrame variable.\n",
            "  Labels appear in describe().\n\n",
            "  Example:\n",
            "    label(df, lnY, \"Log GDP per capita\")\n",
            "    describe(df)\n",
        ),
        "mutate" => "mutate(df, col1 = expr1, col2 = expr2, ...)\n  Generate multiple columns at once. Expressions use DataFrame context.\n  Returns new DataFrame. Works with pipe.\n\n  let df2 = mutate(df, z = x^2, w = ln(y), ratio = x / y)\n  let df2 = df |> mutate(z = x * 2) |> filter(z > 5)\n",
        "drop" => "drop(df, col1, col2, ...)\n  Remove columns from DataFrame.\n  Returns new DataFrame.\n\n  let df2 = drop(df, col_a, col_b)\n",
        "keep" | "select" => "keep(df, col1, col2, ...) / select(df, col1, col2, ...)\n  Keep only specified columns.\n  Returns new DataFrame.\n\n  let df2 = keep(df, price, mpg)\n  let df2 = df |> select(price, mpg)\n",
        "drop_collinear" => "drop_collinear(df [, vars=[x1, x2, ...]])\n  Remove perfectly collinear columns via QR decomposition.\n  If vars omitted, checks all numeric columns.\n\n  let df2 = drop_collinear(df)\n  let df2 = drop_collinear(df, vars=[x1, x2, x3])\n",
        "dataframe" => "dataframe({\"col1\": [1, 2], \"col2\": [3, 4]})\n  Build a DataFrame from a dict of lists.\n\n  let df = dataframe({\"x\": [1, 2, 3], \"y\": [4, 5, 6]})\n",
        "dropna" => "dropna(df [, col1, col2, ...])\n  Remove rows with missing values.\n  If columns specified, checks only those.\n\n  let clean = dropna(df)\n  let clean = dropna(df, price, mpg)\n",
        "rename" => "rename(df, old, new)\n  Rename a column.\n\n  let df2 = rename(df, old_name, new_name)\n",
        "sort" => "sort(df, var1 [, var2, ...] [, desc=true])\nsort(list)\n  Sort DataFrame by columns or sort a list.\n\n  let df2 = sort(df, price)\n  let s = sort([3, 1, 2])  // [1, 2, 3]\n",
        "merge" => "merge(df1, df2, key=col [, type=left|inner|outer])\n  Merge two DataFrames by key column.\n\n  let merged = merge(df1, df2, key=id)\n  let merged = merge(df1, df2, key=id, type=left)\n",
        "append" => "append(df1, df2)\n  Stack two DataFrames vertically.\n\n  let combined = append(df1, df2)\n",
        "rbind" => "rbind(list_of_dfs)\n  Concatenate a list of DataFrames vertically (row-bind).\n  Skips nil entries (useful with parallel for).\n\n  let combined = rbind(results)\n",
        "collapse" => "collapse(df, stat, var1 [, var2, ...] [, by=group])\n  Aggregate by group. Stats: mean, sd, min, max, median, count, sum.\n\n  let agg = collapse(df, mean, price, mpg, by=foreign)\n",
        "group_by" | "groupby" => "group_by(df, by_col, stat, var1 [, var2, ...])\n  Aggregate by group (pipe-friendly). Stats: mean, sd, min, max, median, count, sum.\n\n  let agg = group_by(df, setor, mean, ret, vol)\n  let agg = df |> group_by(setor, mean, ret)\n",
        "pivot_longer" => "pivot_longer(df, stubs=[...], i=id_col, j=time_col)\n  Reshape wide to long by stub prefixes.\n\n  let long = pivot_longer(df, stubs=[\"gdp\", \"pop\"], i=country, j=year)\n  let long = df |> pivot_longer(stubs=[\"gdp\"], i=id, j=year)\n",
        "pivot_wider" => "pivot_wider(df [, var1, ...], i=id_col, j=time_col [, values=var])\n  Reshape long to wide.\n\n  let wide = pivot_wider(df, i=id, j=year, values=gdp)\n  let wide = df |> pivot_wider(i=id, j=year)\n",
        "reshape" => "reshape(df, id=col, stubs=[s1, s2])\n  Reshape wide to long.\n\n  let long = reshape(df, id=country, stubs=[gdp, pop])\n",
        "filter" => "filter(df, condition)\n  Filter rows by condition.\n\n  let sub = filter(df, mpg > 25)\n  let sub = filter(df, price > 5000 & foreign == 1)\n",
        "recode" => "recode(df, var, from=[...], to=[...])\n  Recode values of a column.\n\n  recode(df, region, from=[1,2,3], to=[10,20,30])\n",
        "destring" => "destring(df, var)\n  Convert string column to numeric.\n\n  destring(df, age)\n",
        "summarize" | "sum" => "summarize(df [, var1, var2, ...] [, detail=true])\n  Descriptive statistics. detail=true adds percentiles, skewness, kurtosis.\n\n  summarize(df)\n  summarize(df, price, mpg, detail=true)\n",
        "tabulate" | "tab" => "tabulate(df, var1 [, var2] [, chi2=true])\n  Frequency table. Two vars gives cross-tabulation.\n\n  tabulate(df, foreign)\n  tabulate(df, foreign, rep78, chi2=true)\n",
        "tabstat" => "tabstat(df, var1 [, var2, ...], stats=[\"mean\", \"sd\", \"n\"] [, by=group])\n  Summary statistics table.\n\n  tabstat(df, price, mpg, stats=[\"mean\", \"sd\", \"min\", \"max\"])\n",
        "median" => "median(list) | median(df, x) | median(df, x, if=cond)\n  Median of a numeric list or DataFrame column.\n\n  display median([1, 3, 2])\n  display median(df, price)\n  display median(df, price, if=foreign == 1)\n",
        "xtsum" => "xtsum(df, var1 [, var2, ...], id=entity_col)\n  Panel summary: within/between decomposition.\n  Requires id= entity column.\n\n  xtsum(df, wage, hours, id=firm)\n",
        "correlate" | "corr" => "correlate(df, var1, var2 [, var3, ...])\n  Correlation matrix.\n\n  correlate(df, price, mpg, weight)\n",
        "pwcorr" => "pwcorr(df, var1, var2 [, var3, ...])\n  Pairwise correlations with significance stars.\n\n  pwcorr(df, price, mpg, weight)\n",
        "ci" | "ci_means" => "ci(df, var [, level=0.95])\n  Confidence interval for the mean.\n\n  ci(df, price)\n  ci(df, price, level=0.99)\n",
        "centile" => "centile(df, var [, percentiles=[25, 50, 75]])\n  Arbitrary percentiles.\n\n  centile(df, price)\n  centile(df, price, percentiles=[10, 50, 90])\n",
        "count" => "count(df [, if=condition])\n  Count observations.\n\n  count df\n  count df if price > 5000\n",
        "describe" => "describe(df)\n  Show variable names, types, and labels.\n\n  describe(df)\n",
        "codebook" => "codebook(df [, var1, var2, ...])\n  Detailed variable description: type, unique values, missing, range, percentiles.\n\n  codebook(df)\n  codebook(df, price, mpg)\n",
        "ttest" => "ttest(df, var [, mu=value | by=group | var2, paired=true])\n  T-test: one-sample, two-sample, or paired.\n\n  ttest(df, price, mu=6000)\n  ttest(df, price, by=foreign)\n  ttest(df, x, y, paired=true)\n",
        "poisson" => "poisson(formula, df [, cov=...])\n  Poisson regression (count data).\n\n  let m = poisson(visits ~ age + income, df)\n",
        "nbreg" | "negbin" => "nbreg(formula, df [, cov=...])\n  Negative binomial regression.\n\n  let m = nbreg(visits ~ age + income, df)\n",
        "tobit" => "tobit(formula, df [, ll=0] [, ul=value])\n  Tobit censored regression.\n\n  let m = tobit(hours ~ educ + age, df, ll=0)\n",
        "heckman" => "heckman(formula, df, select=formula)\n  Heckman selection model.\n\n  let m = heckman(wage ~ educ + exper, df, select=lfp ~ age + kids)\n",
        "qreg" | "quantile" => "qreg(formula, df [, q=0.5])\n  Quantile regression.\n\n  let m = qreg(price ~ mpg + weight, df, q=0.25)\n",
        "cox" => "cox(formula, df [, time=var])\n  Cox proportional hazards model.\n\n  let m = cox(died ~ drug + age, df, time=studytime)\n",
        "lasso" => "lasso(formula, df [, lambda=value])\n  Lasso (L1) regularization.\n\n  let m = lasso(Y ~ X1 + X2 + X3, df)\n",
        "ridge" => "ridge(formula, df [, lambda=value])\n  Ridge (L2) regularization.\n\n  let m = ridge(Y ~ X1 + X2 + X3, df)\n",
        "elasticnet" | "enet" => "elasticnet(formula, df [, alpha=0.5] [, lambda=value])\n  Elastic net regularization.\n\n  let m = elasticnet(Y ~ X1 + X2, df, alpha=0.5)\n",
        "ab" | "arellano_bond" => "ab(formula, df, id=var [, time=var])\n  Arellano-Bond dynamic panel estimator.\n\n  let m = ab(Y ~ X1 + X2, df, id=firm, time=year)\n",
        "sysgmm" => "sysgmm(formula, df, id=var [, time=var])\n  System GMM (Blundell-Bond) estimator.\n\n  let m = sysgmm(Y ~ X1 + X2, df, id=firm, time=year)\n",
        "pcse" => "pcse(formula, df, id=var, time=var)\n  Panel-corrected standard errors (Beck-Katz).\n\n  let m = pcse(Y ~ X1 + X2, df, id=country, time=year)\n",
        "xtgls" => "xtgls(formula, df, id=var, time=var)\n  Feasible GLS for panel data.\n\n  let m = xtgls(Y ~ X1 + X2, df, id=country, time=year)\n",
        "sur" => "sur(df, y1 ~ x1 + x2, y2 ~ x3 + x4, ...)\n  Seemingly Unrelated Regressions (Zellner FGLS).\n  Alias: sureg\n\n  let m = sur(df, invest ~ value + capital, consump ~ income)\n",
        "garch" => "garch(df, var [, p=1, q=1, dist=normal|t])\n  GARCH(p,q) volatility model.\n\n  let m = garch(df, returns, p=1, q=1)\n",
        "egarch" => "egarch(df, var [, p=1, q=1])\n  EGARCH (asymmetric volatility).\n\n  let m = egarch(df, returns)\n",
        "arima" => "arima(df, var, p=_, d=_, q=_ [, P=_, D=_, Q=_, s=_])\n  ARIMA / SARIMA model.\n\n  let m = arima(df, gdp, p=1, d=1, q=1)\n  let m = arima(df, sales, p=1, d=1, q=1, P=1, D=1, Q=1, s=12)\n",
        "autoreg" => "autoreg(df, var [, lags=1, trend=\"c\"])\n  Autoregressive model AR(p) via OLS.\n  trend: \"c\" (constant), \"ct\" (const+trend), \"t\" (trend), \"n\" (none)\n\n  let m = autoreg(df, y, lags=2)\n  let m = autoreg(df, y, lags=4, trend=\"ct\")\n",
        "ardl" => "ardl(y ~ x1 + x2, df [, lags=p, xlags=q])\n  Autoregressive Distributed Lag ARDL(p,q).\n  lags: number of lags of y; xlags: lags of each regressor.\n\n  let m = ardl(y ~ x, df, lags=1, xlags=1)\n  let m = ardl(gdp ~ inv + exp, df, lags=2, xlags=2)\n",
        "kalman" => "kalman(df, var [, model=\"ll\"|\"llt\", sigma_obs=s, sigma_state=s])\n  Kalman filter/smoother (Rauch-Tung-Striebel).\n  model=\"ll\"  — Local Level (level + noise)\n  model=\"llt\" — Local Linear Trend (level + slope + noise)\n  sigmas: auto-estimated if omitted.\n  Adds {var}_filtered and {var}_smoothed to the DataFrame.\n  LLT also adds {var}_slope_filtered and {var}_slope_smoothed.\n\n  kalman(df, y, model=\"ll\", sigma_obs=1.0, sigma_state=0.1)\n  kalman(df, gdp, model=\"llt\")\n",
        "var" => "var(df, var1, var2 [, var3, ...] [, lags=p])\n  Vector autoregression.\n\n  let m = var(df, gdp, inflation, lags=2)\n",
        "vecm" => "vecm(df, var1, var2 [, ...] [, lags=p, rank=r])\n  Vector error correction model.\n\n  let m = vecm(df, gdp, consumption, lags=2, rank=1)\n",
        "svar" => "svar(df, var1, var2 [, ...] [, lags=p, type=cholesky])\n  Structural VAR.\n\n  let m = svar(df, gdp, inflation, lags=2)\n",
        "irf" => "irf(model [, periods=20])\n  Impulse response function from VAR/SVAR.\n\n  irf(m_var, periods=20)\n",
        "fevd" => "fevd(model [, periods=20])\n  Forecast error variance decomposition.\n\n  fevd(m_var, periods=20)\n",
        "did" => "did(formula, df, treat=var, post=var)\n  Difference-in-differences.\n\n  let m = did(Y ~ X1, df, treat=treated, post=after)\n",
        "rd" => "rd(formula, df, running=var, cutoff=value)\n  Regression discontinuity design.\n\n  let m = rd(Y ~ X, df, running=score, cutoff=50)\n",
        "fuzzy_rd" => "fuzzy_rd(outcome ~ running, \"treatment_col\", cutoff, df [, bw=h, poly=1])\n  Fuzzy Regression Discontinuity (treatment compliance imperfect).\n\n  let m = fuzzy_rd(Y ~ score, \"treated\", 50, df, bw=10, poly=1)\n",
        "synth" => "synth(df, outcome=var, treat_unit=id, treat_time=t, id=var, time=var)\n  Synthetic control method.\n\n  let m = synth(df, outcome=gdp, treat_unit=3, treat_time=2000, id=state, time=year)\n",
        "psm" | "psmatch" => "psm(formula, df [, k=1, caliper=0.05])\n  Propensity score matching.\n\n  let m = psm(Y ~ X1 + X2, df, k=1, caliper=0.05)\n",
        "glm" => "glm(formula, df, family=gaussian|binomial|poisson|gamma|negbin|tweedie [, link=...])\n  Generalized linear model.\n\n  let m = glm(Y ~ X, df, family=binomial, link=probit)\n",
        "rlm" | "huber" => "rlm(formula, df [, method=huber|bisquare])\n  Robust linear model (M-estimation).\n\n  let m = rlm(Y ~ X1 + X2, df)\n",
        "gee" => "gee(formula, df, id=var [, family=gaussian, corr=exchangeable])\n  Generalized estimating equations.\n\n  let m = gee(Y ~ X1 + X2, df, id=subject)\n",
        "betareg" => "betareg(formula, df)\n  Beta regression (proportions 0-1).\n\n  let m = betareg(share ~ X1 + X2, df)\n",
        "cloglog" => "cloglog(formula, df)\n  Complementary log-log model.\n\n  let m = cloglog(Y ~ X1 + X2, df)\n",
        "ologit" | "oprobit" => "ologit(formula, df) / oprobit(formula, df)\n  Ordered logit/probit.\n\n  let m = ologit(rating ~ X1 + X2, df)\n",
        "mlogit" => "mlogit(formula, df)\n  Multinomial logit.\n\n  let m = mlogit(choice ~ X1 + X2, df)\n",
        "zip" => "zip(formula, df [, inflate=formula])\n  Zero-inflated Poisson.\n\n  let m = zip(visits ~ age + income, df)\n",
        "zinb" => "zinb(formula, df [, inflate=formula])\n  Zero-inflated negative binomial.\n\n  let m = zinb(visits ~ age + income, df)\n",
        "mixed" => "mixed(formula, df, id=var)\n  Mixed-effects / hierarchical linear model.\n\n  let m = mixed(score ~ treatment, df, id=school)\n",
        "glsar" => "glsar(formula, df [, lags=1])\n  GLS with AR errors.\n\n  let m = glsar(Y ~ X1 + X2, df, lags=2)\n",
        "km" | "kaplan_meier" => "km(df, time=var, event=var [, by=group])\n  Kaplan-Meier survival curve.\n\n  km(df, time=studytime, event=died, by=drug)\n",
        "hausman" => "hausman(m_fe, m_re)\n  Hausman specification test (FE vs RE).\n\n  hausman(m_fe, m_re)\n",
        "lincom" => "lincom(model, expr)\n  Linear combination of coefficients.\n\n  lincom(m, X1 + X2)\n",
        "vif" => "vif(model)\n  Variance inflation factors.\n\n  vif(m)\n",
        "influence" => "influence(model)\n  Influence diagnostics: DFFITS, Cook's D, leverage.\n\n  influence(m)\n",
        "ic" | "estat" | "fitstat" | "estat_ic" => "ic(m1, m2 [, ...])\nestat(m1, m2 [, ...])\n  AIC/BIC comparison.\n\n  ic(m1, m2, m3)\n",
        "scatter" | "graph_scatter" => "scatter(df, x, y) / graph_scatter(df, x, y, path=\"f.svg\")\n  Scatter plot (ASCII or SVG).\n\n  scatter(df, mpg, price)\n  graph_scatter(df, mpg, price, path=\"fig.svg\")\n",
        "histogram" | "graph_hist" => "histogram(df, var [, bins=30]) / graph_hist(df, var, path=\"f.svg\")\n  Histogram (ASCII or SVG).\n\n  histogram(df, price)\n",
        "graph_line" => "graph_line(df, x, y, path=\"f.svg\")\n  Line plot (SVG).\n\n  graph_line(df, year, gdp, path=\"trend.svg\")\n",
        "graph_coef" => "graph_coef(model, path=\"f.svg\")\n  SVG coefficient plot with 95% CI.\n\n  graph_coef(m, path=\"coef.svg\")\n",
        "boxplot" => "boxplot(df, var)\n  Box plot (ASCII).\n\n  boxplot(df, price)\n",
        "kdensity" => "kdensity(df, var)\n  Kernel density plot (ASCII).\n\n  kdensity(df, price)\n",
        "acfplot" | "pacfplot" => "acfplot(df, var [, lags=20])\npacfplot(df, var [, lags=20])\n  ACF/PACF correlogram.\n\n  acfplot(df, returns, lags=30)\n",
        "acf" | "pacf" => "acf(df, var [, lags=20])\npacf(df, var [, lags=20])\n  Returns ACF/PACF values as a list. Also accepts a model (uses residuals).\n\n  acf(df, returns, lags=30)\n  pacf(m_ols, lags=10)\n",
        "cusumtest" => "cusumtest(model)\n  CUSUM test for structural stability (Brown-Durbin-Evans 1975).\n  Uses recursive residuals; checks if cumulative sum stays within 5% bounds.\n\n  cusumtest(m_ols)\n",
        "akaike_weights" | "aic_weights" => "akaike_weights(m1, m2, ...)\n  Returns Akaike weights as a dict {model_name: weight}.\n  Supports OLS, logit/probit, Poisson, NegBin, Tobit, Ordered, Mixed, ZI.\n\n  akaike_weights(m1, m2, m3)\n",
        "lrtest" | "lr_test" => "lrtest(m_restricted, m_unrestricted)\n  Likelihood-ratio test for nested models.\n  H0: restricted model is adequate (additional parameters are zero).\n  LR = -2*(lnL_restricted - lnL_unrestricted) ~ chi²(df).\n  Supports OLS, logit/probit, Poisson, NegBin, Tobit, Ordered, Mixed, ZI, GLM, GARCH, ARIMA.\n\n  lrtest(m1, m2)\n",
        "estat_overid" | "sargan" | "overid" => "estat_overid(endog_formula, instrument_formula, df)\n  Sargan / Hansen J overidentification test.\n  H0: instruments are exogenous (valid).\n  Only applicable when overidentified (L > K).\n\n  estat_overid(y ~ x1 + x_endog, ~ z1 + z2, df)\n",
        "estat_endog" | "dwh" => "estat_endog(endog_formula, instrument_formula, df)\n  Durbin-Wu-Hausman endogeneity test.\n  H0: regressors are exogenous (OLS is consistent).\n  If rejected, IV is needed.\n\n  estat_endog(y ~ x1 + x_endog, ~ z1 + z2, df)\n",
        "estat_classification" | "classification" => "estat_classification(model [, threshold=0.5])\n  Classification table for logit/probit.\n  Reports sensitivity, specificity, and correct rate.\n\n  estat_classification(m_logit)\n  estat_classification(m_logit, threshold=0.3)\n",
        "lroc" | "roc" => "lroc(model)\n  ROC curve and AUC for logit/probit.\n  AUC > 0.5 indicates discrimination power.\n\n  lroc(m_logit)\n",
        "estat_gof" | "hosmer_lemeshow" => "estat_gof(model [, groups=10])\n  Hosmer-Lemeshow goodness-of-fit test for logit/probit.\n  H0: model fits the data adequately.\n\n  estat_gof(m_logit)\n  estat_gof(m_logit, groups=5)\n",
        "linktest" => "linktest(model)\n  Specification test for logit/probit.\n  Re-estimates the model using ŷ and ŷ² as regressors.\n  H0: model is correctly specified (coef of ŷ² = 0).\n  If ŷ² is significant, there is a specification error.\n\n  linktest(m_logit)\n",
        "xtlogit" => "xtlogit(y ~ x1 + x2, df, id=\"group_col\" [, corr=exchangeable])\n  Panel logit via GEE (population-averaged).\n  corr: independence, exchangeable (default), ar1, unstructured.\n\n  xtlogit(y ~ x1 + x2, df, id=\"firm\")\n",
        "xtprobit" => "xtprobit(y ~ x1 + x2, df, id=\"group_col\" [, corr=exchangeable])\n  Panel probit via GEE (population-averaged).\n\n  xtprobit(y ~ x1 + x2, df, id=\"firm\")\n",
        "xtpoisson" => "xtpoisson(y ~ x1 + x2, df, id=\"group_col\" [, corr=exchangeable])\n  Panel Poisson via GEE (population-averaged).\n\n  xtpoisson(y ~ x1 + x2, df, id=\"firm\")\n",
        "eventstudy" | "event_study" => "eventstudy(y ~ event_time + controls, df [, ref=-1, min=-5, max=5, cov=HC1])\n  Event study (dynamic DiD with leads and lags).\n  Estimates event-time dummies relative to reference period.\n\n  eventstudy(y ~ etime + x1, df, ref=-1, min=-3, max=3)\n",
        "nls_exp" => "nls_exp(y ~ x, df, start=[a, b])\n  Nonlinear least squares: y = a * exp(b * x).\n  Levenberg-Marquardt with numerical gradients.\n\n  nls_exp(y ~ x, df, start=[1.0, 0.5])\n",
        "nls_power" => "nls_power(y ~ x, df, start=[a, b])\n  Nonlinear least squares: y = a * x^b.\n\n  nls_power(y ~ x, df, start=[1.0, 0.5])\n",
        "nls_logistic" => "nls_logistic(y ~ x, df, start=[a, b, c])\n  Nonlinear least squares: y = a / (1 + exp(-b*(x-c))).\n\n  nls_logistic(y ~ x, df, start=[100.0, 1.0, 5.0])\n",
        "nls_cobb_douglas" => "nls_cobb_douglas(y ~ x1 + x2, df, start=[a, b0, b1])\n  Nonlinear least squares: y = a * x1^b0 * x2^b1.\n  Cobb-Douglas production function.\n\n  nls_cobb_douglas(output ~ capital + labor, df, start=[1.0, 0.3, 0.7])\n",
        "nls_ces" => "nls_ces(y ~ x1 + x2, df, start=[a, b1, b2, rho])\n  Nonlinear least squares: y = a * (b1*x1^rho + b2*x2^rho)^(1/rho).\n  CES production function.\n\n  nls_ces(output ~ k + l, df, start=[1.0, 0.5, 0.5, -0.5])\n",
        "marginsplot" | "margins_plot" => "marginsplot(model [, width=50])\n  Plot average marginal effects (AME) for logit/probit.\n  Horizontal bar chart with 95% confidence intervals.\n\n  marginsplot(m_logit)\n",
        "spatial_sar" => "spatial_sar(y ~ x1 + x2, df, w=W)\n  Spatial Autoregressive model: y = rho*Wy + X*beta + epsilon.\n  Maximum likelihood estimation. W is a row-standardized weights matrix\n  provided as a list of lists.\n\n  let W = [[0, 0.5, 0.5], [0.5, 0, 0.5], [0.5, 0.5, 0]]\n  spatial_sar(y ~ x1 + x2, df, w=W)\n",
        "spatial_sem" => "spatial_sem(y ~ x1 + x2, df, w=W)\n  Spatial Error model: y = X*beta + u, u = lambda*Wu + epsilon.\n  FGLS estimation with spatial error autocorrelation.\n\n  let W = [[0, 0.5, 0.5], [0.5, 0, 0.5], [0.5, 0.5, 0]]\n  spatial_sem(y ~ x1 + x2, df, w=W)\n",
        "double_ml" | "dml" => "double_ml(y ~ d + x1 + x2, df [, folds=5, poly=2])\n  Double/debiased ML (Chernozhukov 2018).\n  Partially linear model: Y = theta*D + g(X) + epsilon.\n  K-fold cross-fitting with polynomial nuisance models.\n  First RHS variable is treatment, rest are controls.\n\n  double_ml(y ~ treatment + x1 + x2, df, folds=5)\n",
        "sfa_production" | "frontier" => "sfa_production(y ~ x1 + x2, df)\n  Stochastic production frontier: y = alpha + beta*x + v - u.\n  Half-normal inefficiency (u >= 0). MLE via grid search.\n  Reports sigma_v, sigma_u, lambda, gamma, technical efficiency.\n\n  sfa_production(log_y ~ log_k + log_l, df)\n",
        "sfa_cost" => "sfa_cost(y ~ x1 + x2, df)\n  Stochastic cost frontier: y = alpha + beta*x + v + u.\n  Half-normal inefficiency (u >= 0 increases cost).\n\n  sfa_cost(log_cost ~ log_price + log_output, df)\n",
        "panel_tobit" => "panel_tobit(y ~ x1 + x2, df, id=\"firm\" [, censor=0])\n  Panel Tobit with random effects.\n  y_it = max(censor, x_it'beta + alpha_i + epsilon_it).\n  EM-style MLE with variance components estimation.\n\n  panel_tobit(investment ~ cash_flow, df, id=\"firm\", censor=0)\n",
        "panel_heckman" => "panel_heckman(y ~ x1 + x2, df, sel=\"z ~ w1 + w2\", id=\"firm\")\n  Panel Heckman (selection with random effects).\n  Two-step: probit selection + OLS outcome with IMR.\n  Cluster-robust SE. Reports rho, sigma_alpha, sigma_nu.\n\n  panel_heckman(wage ~ educ + exper, df, sel=\"particip ~ educ + kids\", id=\"woman\")\n",
        "spatial_panel_sar" => "spatial_panel_sar(y ~ x1 + x2, df, w=W, id=\"entity\")\n  Spatial panel SAR with fixed effects.\n  y_it = rho*W*y_it + x_it'beta + mu_i + epsilon_it.\n  Within transformation + grid search for rho.\n\n  spatial_panel_sar(gdp ~ capital + labor, df, w=W, id=\"country\")\n",
        "spatial_panel_sem" => "spatial_panel_sem(y ~ x1 + x2, df, w=W, id=\"entity\")\n  Spatial panel SEM with fixed effects.\n  y_it = x_it'beta + mu_i + u_it, u_it = lambda*W*u_it + epsilon_it.\n\n  spatial_panel_sem(gdp ~ capital + labor, df, w=W, id=\"country\")\n",
        "bayes_sfa_production" | "bayes_frontier" => "bayes_sfa_production(y ~ x1 + x2, df [, burn=1000, draws=2000])\n  Bayesian stochastic production frontier via MCMC (Gibbs sampler).\n  y = alpha + beta*x + v - u. Half-normal inefficiency.\n  Priors: beta ~ N(0,100), sigma_v² ~ IG(2,2), sigma_u² ~ IG(2,2).\n  Reports posterior means, SDs, 95% credible intervals.\n\n  bayes_sfa_production(log_y ~ log_k + log_l, df, burn=1000, draws=2000)\n",
        "bayes_sfa_cost" => "bayes_sfa_cost(y ~ x1 + x2, df [, burn=1000, draws=2000])\n  Bayesian stochastic cost frontier via MCMC.\n  y = alpha + beta*x + v + u. Half-normal inefficiency.\n\n  bayes_sfa_cost(log_cost ~ log_price + log_output, df)\n",
        "midas" => "midas(y ~ x, df [, freq=3, lags=12, poly=2])\n  Mixed Data Sampling regression (Ghysels et al.).\n  Low-freq y regressed on high-freq x via Almon polynomial weights.\n  freq = frequency ratio (3=monthly→quarterly).\n  lags = number of high-freq lags. poly = Almon polynomial degree.\n\n  midas(gdp ~ industrial_production, df, freq=3, lags=12, poly=2)\n",
        "tvp" => "tvp(y ~ x1 + x2, df)\n  Time-Varying Parameter regression via Kalman filter.\n  y_t = x_t'beta_t + eps,  beta_t = beta_{t-1} + eta.\n  MLE for sigma_eps and sigma_eta via grid search + golden section.\n  Reports smoothed beta_t estimates.\n\n  tvp(inflation ~ unemployment + gap, df)\n",
        "setar" => "setar(y, df [, order=2, delay=1])\n  Self-Exciting Threshold Autoregression.\n  Two regimes split by y_{t-delay} threshold (grid search).\n  order = AR order per regime. delay = threshold lag.\n\n  setar(gdp, df, order=2, delay=1)\n",
        "panel_qreg" | "panel_quantile" => "panel_qreg(y ~ x1 + x2, df, id=\"firm\" [, tau=0.5])\n  Panel quantile regression with fixed effects.\n  Within transformation + quantile regression (Koenker 2004).\n  tau = quantile level (0-1).\n\n  panel_qreg(wage ~ educ + exper, df, id=\"firm\", tau=0.9)\n",
        "msvar" | "ms_var" => "msvar(y1 + y2, df [, regimes=2, lags=1])\n  Markov-Switching VAR with K regimes.\n  y_t = mu_{s_t} + A*y_{t-1} + eps, eps ~ N(0, Sigma_{s_t}).\n  EM (Baum-Welch) estimation. Reports transition matrix,\n  regime intercepts, filtered/smoothed probabilities.\n\n  msvar(gdp + inflation, df, regimes=2, lags=1)\n",
        "favar" => "favar(y1 + y2 + y3, df, observed=\"rate\" [, factors=2, lags=1, irf=0])\n  Factor-Augmented VAR (Bernanke et al. 2005).\n  PCA factors from large panel + observed policy variable.\n  Two-step: PCA extraction + VAR on [F, R].\n  irf = IRF horizon (0=no IRF).\n\n  favar(ip + cpi + emp, df, observed=\"fed_rate\", factors=2, lags=1, irf=12)\n",
        "spatial_durbin" | "sdm" => "spatial_durbin(y ~ x1 + x2, df, w=W, id=\"entity\")\n  Spatial Durbin Model (panel, fixed effects).\n  y = rho*W*y + X*beta + W*X*theta + FE + eps.\n  Nests SAR (theta=0) and SLX (rho=0).\n  Reports direct (beta) and indirect (theta) effects.\n\n  spatial_durbin(gdp ~ capital + labor, df, w=W, id=\"country\")\n",
        "johansen_break" => "johansen_break(y1 ~ y2, df [, lags=1, breaks=[50]])\n  Johansen cointegration test with structural breaks.\n  Shift dummies at break points. Trace and Lambda-max tests.\n  breaks = list of break time indices.\n\n  johansen_break(gdp ~ consumption, df, lags=1, breaks=[50])\n",
        "tvp_var" => "tvp_var(y1 ~ y2, df [, lags=1])\n  Time-Varying Parameter VAR via Kalman filter.\n  y_t = Z_t'*B_t + eps, B_t = B_{t-1} + eta.\n  MLE for Sigma and Q via grid search. Reports smoothed B_t.\n\n  tvp_var(gdp ~ inflation, df, lags=1)\n",
        "spatial_durbin_error" | "sdem" => "spatial_durbin_error(y ~ x1 + x2, df, w=W, id=\"entity\")\n  Spatial Durbin Error Model (panel, fixed effects).\n  y = X*beta + W*X*theta + FE + u, u = lambda*W*u + eps.\n  Combines SLX (spatially lagged X) with SEM (spatial error).\n  Reports direct (beta) and indirect (theta) effects, lambda.\n\n  spatial_durbin_error(gdp ~ capital + labor, df, w=W, id=\"country\")\n",
        "fmols" => "fmols(y ~ x1 + x2, df)\n  Fully Modified OLS (Phillips & Hansen 1990).\n  Nonparametric correction for endogeneity and serial correlation\n  in cointegrating regressions. Bartlett kernel long-run covariance.\n\n  fmols(log_consumption ~ log_income, df)\n",
        "qvar" | "quantile_var" => "qvar(y1 ~ y2, df [, lags=1, tau=0.5, boot=100])\n  Quantile VAR — equation-by-equation quantile regression.\n  Captures quantile-specific dynamics (e.g., recession vs expansion).\n  tau = quantile level. boot = bootstrap replications for SE.\n\n  qvar(gdp ~ inflation, df, lags=1, tau=0.9)\n",
        "dfm" => "dfm(df, y1, y2, ... [, factors=2, order=1])\n  Dynamic Factor Model (existing command).\n  Extracts common factors from multiple series.\n  factors = number of factors. order = factor AR order.\n\n  dfm(df, ip, cpi, emp, factors=2, order=1)\n",
        "pstr" => "pstr(y ~ x1 + x2, df, q=\"transition_var\", id=\"entity\")\n  Panel Smooth Transition Regression (fixed effects).\n  y = mu_i + beta0'*x + beta1'*x*g(q;gamma,c) + eps.\n  g(q) = 1/(1+exp(-gamma*(q-c))). Grid search on (gamma, c).\n  Reports beta0 (linear), beta1 (nonlinear), gamma, c.\n\n  pstr(gdp ~ capital + labor, df, q=\"gdp_growth\", id=\"country\")\n",
        "modwt" => "modwt(df, var [, scales=4])\n  Maximal Overlap Discrete Wavelet Transform (Haar).\n  Decomposes series into multi-scale components (time-frequency).\n  Reports wavelet/scaling coefficients, energy per scale.\n  scales = number of decomposition levels.\n\n  modwt(df, gdp, scales=4)\n",
        "copula" => "copula(y1 ~ y2, df [, type=\"gaussian\"])\n  Copula-based dependence modeling (Sklar's theorem).\n  type: gaussian, clayton, gumbel, frank.\n  Two-step: empirical CDF margins + copula parameter MLE.\n  Reports Kendall's tau, Spearman's rho, copula parameter.\n\n  copula(returns_a ~ returns_b, df, type=\"clayton\")\n",
        "nardl" => "nardl(y ~ x, df [, lags=1])\n  Nonlinear ARDL (Shin, Yu & Greenwood-Nimmo 2014).\n  Asymmetric cointegration: decomposes x into positive/negative\n  partial sums. Reports long-run multipliers (beta+, beta-),\n  speed of adjustment (rho), short-run coefficients, asymmetry tests.\n\n  nardl(consumption ~ income, df, lags=2)\n",
        "pvar" | "panel_var" => "pvar(y1 ~ y2, df, id=\"entity\" [, lags=1])\n  Panel VAR via GMM (Holtz-Eakin, Newey & Rosen 1988).\n  Arellano-Bond style: lagged levels as instruments for\n  first-differenced equations. Reports per-equation coefficients,\n  J-test for overidentifying restrictions.\n\n  pvar(gdp ~ inflation, df, id=\"country\", lags=1)\n",
        "fcoef" | "functional_coef" => "fcoef(y ~ x1 + x2, df, z=\"moderator\" [, points=20])\n  Functional coefficient model (Hastie & Tibshirani 1993).\n  Local linear kernel regression: coefficients vary smoothly\n  with moderator z. Gaussian kernel, Silverman bandwidth.\n  Reports coefficients at evaluation points.\n\n  fcoef(wage ~ experience + education, df, z=\"age\", points=30)\n",
        "dcc_garch" | "dcc" => "dcc_garch(y1 ~ y2, df)\n  DCC-GARCH (Engle 2002). Dynamic Conditional Correlation.\n  Two-step: univariate GARCH(1,1) per series + DCC for\n  time-varying correlation matrix. Reports DCC alpha/beta,\n  GARCH params, conditional volatilities, correlation matrices.\n\n  dcc_garch(returns_a ~ returns_b, df)\n",
        "tvar" | "threshold_var" => "tvar(y1 ~ y2, df, q=\"threshold_var\" [, lags=1, delay=1])\n  Threshold VAR (Tong 1978, Tsay 1998). Regime switching via\n  threshold variable: different VAR coefficients in low/high\n  regimes. Grid search over threshold c and delay d.\n\n  tvar(gdp ~ inflation, df, q=\"gdp_growth\", lags=1, delay=1)\n",
        "bvar" | "bayesian_var" => "bvar(y1 ~ y2, df [, lags=1, lambda1=0.1, lambda2=0.2, lambda3=1.0])\n  Bayesian VAR with Minnesota prior (Litterman 1986).\n  Random walk prior: shrinks own lags toward 1, cross lags\n  toward 0. lambda1=own lag tightness, lambda2=cross lag,\n  lambda3=higher lag decay. Closed-form posterior.\n\n  bvar(gdp ~ inflation, df, lags=2, lambda1=0.1)\n",
        "mfvar" | "mixed_freq_var" => "mfvar(df_low, y_low1, ..., df_high, y_high1, ... [, agg=3, lags=1])\n  Mixed-Frequency VAR (Foroni-Ghysels-Marcellino 2013).\n  Combines low-freq + high-freq variables via MIDAS exponential\n  Almon aggregation. agg=high periods per low period.\n\n  mfvar(df_q, gdp, df_m, cpi, agg=3, lags=1)\n",
        "tvcopula" | "tv_copula" => "tvcopula(y1 ~ y2, df [, type=\"gaussian\"])\n  Time-varying copula (Patton 2006). GARCH-like dynamics for\n  copula parameter: theta_t = g(a + b*theta_{t-1} + c*psi_{t-1}).\n  type: gaussian, clayton, gumbel. Reports theta path, Kendall tau.\n\n  tvcopula(returns_a ~ returns_b, df, type=\"clayton\")\n",
        "sv" | "stochastic_vol" => "sv(df, var [, iter=100])\n  Stochastic Volatility (Taylor 1986). Latent log-volatility\n  AR(1) process. Quasi-MCMC via Metropolis-Hastings on h_t.\n  Reports mu, phi (persistence), sigma_eta (vol-of-vol),\n  conditional volatility path.\n\n  sv(df, returns, iter=100)\n",
        "fapanel" | "fa_panel" => "fapanel(y ~ x1 + x2, df, aux=\"aux_df\", id=\"entity\", period=\"period\" [, factors=2])\n  Factor-augmented panel regression. PCA factors from auxiliary\n  panel + FE regression on traditional regressors + factors.\n  Reports beta (regressors), gamma (factors), feature importance.\n\n  fapanel(gdp ~ capital + labor, df, aux=\"macro_df\", id=\"country\", period=\"year\", factors=2)\n",
        "hawkes" => "hawkes(df, time_var [, T=100])\n  Hawkes process (Hawkes 1971). Self-exciting point process:\n  lambda(t) = mu + sum alpha*exp(-beta*(t-t_i)).\n  Grid search MLE. Reports mu, alpha, beta, branching ratio.\n  Stationarity requires branching ratio < 1.\n\n  hawkes(df, event_times, T=100)\n",
        "rf" | "random_forest" => "rf(y ~ x1 + x2, df [, trees=100, depth=10])\n  Random Forest regression (Breiman 2001). Ensemble of CART\n  decision trees with bootstrap sampling + random feature\n  subsampling. Reports feature importance, OOB R-squared.\n\n  rf(price ~ bedrooms + bathrooms + sqft, df, trees=100, depth=10)\n",
        "gbm" | "gradient_boosting" => "gbm(y ~ x1 + x2, df [, trees=100, lr=0.1, depth=3, subsample=1.0])\n  Gradient Boosting regression (Friedman 2001). Sequential\n  additive model of shallow regression trees. Shrinkage (lr)\n  for regularization. Feature importance via impurity decrease.\n\n  gbm(price ~ bedrooms + sqft, df, trees=100, lr=0.1, depth=3)\n",
        "mlp" | "neural_net" => "mlp(y ~ x1 + x2, df [, hidden=10, lr=0.01, epochs=200])\n  Multilayer Perceptron (Rumelhart-Hinton-Williams 1986).\n  Single hidden layer, sigmoid activation. Backpropagation\n  with momentum. Xavier initialization. Standardized internally.\n\n  mlp(price ~ bedrooms + sqft, df, hidden=20, lr=0.01, epochs=500)\n",
        "synthdid" | "synthetic_did" => "synthdid(df, y_var, treated_var, treatment_period, unit=\"col\", period=\"col\")\n  Synthetic DiD (Arkhangelsky et al. 2021). Combines synthetic\n  control + DiD. Unit weights via OLS on pre-period. Placebo SE.\n  Reports ATT, unit/time weights, synthetic control path.\n\n  synthdid(df, gdp, treated, 5, unit=\"country\", period=\"year\")\n",
        "cuped" => "cuped(y ~ x, df, treated=\"treated_var\")\n  CUPED (Deng-Xu-Kohavi-Walker 2013). Adjusts A/B test outcome\n  using pre-treatment covariate: Y_adj = Y - theta*(X - X_bar).\n  theta = Cov(Y,X)/Var(X). Reduces variance, tighter CIs.\n  Reports adjusted vs unadjusted effect, variance reduction.\n\n  cuped(post_revenue ~ pre_revenue, df, treated=\"is_treatment\")\n",
        "qrf" | "quantile_forest" => "qrf(y ~ x1 + x2, df [, quantiles=\"0.1,0.5,0.9\", trees=100, depth=10])\n  Quantile Regression Forest (Meinshausen 2006). Stores all\n  leaf responses, computes weighted empirical CDF for\n  conditional quantile estimation. Reports OOB R-squared,\n  feature importance, quantile predictions.\n\n  qrf(price ~ bedrooms + sqft, df, quantiles=\"0.1,0.5,0.9\")\n",
        "xgboost" | "xgb" => "xgboost(y ~ x1 + x2, df [, trees=100, lr=0.3, depth=6, lambda=1.0, alpha=0.0, gamma=0.0, subsample=1.0, colsample=1.0])\n  XGBoost (Chen & Guestrin 2016). L1/L2 regularized gradient\n  boosting with Newton splits. Second-order approximation.\n  gamma=leaf penalty, lambda=L2, alpha=L1. Feature importance.\n\n  xgboost(price ~ bedrooms + sqft, df, trees=100, lr=0.3, lambda=1.0)\n",
        "dml_crossfit" | "dml_cf" => "dml_crossfit(y ~ d, df, x=\"x1,x2\" [, folds=5])\n  Double ML with cross-fitting (Chernozhukov et al. 2018).\n  Partially linear model: Y = theta*D + g(X) + eps.\n  K-fold cross-fitting for nuisance functions. Reports\n  causal effect theta, SE, CI, nuisance MSE.\n\n  dml_crossfit(y ~ treatment, df, x=\"age,income,education\", folds=5)\n",
        "bsc" | "bayesian_sc" => "bsc(df, y_var, control_vars, treatment_period [, prior=1.0])\n  Bayesian Synthetic Control (Brodersen et al. 2015).\n  Conjugate Normal-Inverse-Gamma posterior. Ridge-like prior\n  on weights. Reports tau (treatment effect), credible\n  interval, weights, counterfactual path.\n\n  bsc(df, gdp, \"gdp_usa,gdp_uk\", 5, prior=1.0)\n",
        "lstm" => "lstm(df, var [, hidden=10, seqlen=10, lr=0.01, epochs=100, forecast=5])\n  LSTM recurrent neural network (Hochreiter-Schmidhuber 1997).\n  Single-layer LSTM with forget/input/output gates.\n  Truncated BPTT training. Standardized internally.\n  Reports fitted values, multi-step forecast, MSE, R².\n\n  lstm(df, gdp, hidden=10, seqlen=12, lr=0.01, epochs=100, forecast=5)\n",
        "causalforest" | "causal_forest" => "causalforest(y ~ treated, df, x=\"x1,x2\" [, trees=100, depth=5])\n  Causal Forest (Wager-Athey 2018). Honest causal trees for\n  heterogeneous treatment effects (HTE). Split sample: one\n  half for splitting, one half for leaf effect estimation.\n  Reports ATE, CATE distribution, feature importance.\n\n  causalforest(y ~ treatment, df, x=\"age,income\", trees=100, depth=5)\n",
        "grf" | "generalized_rf" => "grf(y ~ treated, df, x=\"x1,x2\" [, trees=100, depth=5])\n  Generalized Random Forest (Athey-Tibshirani-Wager 2019).\n  Doubly-robust CATE with local centering. AIPW estimator\n  for ATE. Pseudo-outcome regression for CATE. Propensity\n  and outcome regression via OLS. Reports ATE, CATE, CI.\n\n  grf(y ~ treatment, df, x=\"age,income\", trees=100, depth=5)\n",
        "conformal" | "conformal_pred" => "conformal(y ~ x1 + x2, df [, alpha=0.1, calib=0.3])\n  Conformal Prediction (Vovk-Gammerman-Shafer 2005).\n  Distribution-free prediction intervals with finite-sample\n  coverage guarantee. Split conformal with OLS base predictor.\n  Reports intervals, conformal quantile, empirical coverage.\n\n  conformal(price ~ bedrooms + sqft, df, alpha=0.1)\n",
        "transformer" | "transformer_ts" => "transformer(df, var [, d_model=8, seqlen=10, lr=0.001, epochs=100, forecast=5])\n  Transformer (Vaswani et al. 2017). Single-head, single-layer\n  encoder for time series. Scaled dot-product attention.\n  Sinusoidal positional encoding. ReLU feed-forward.\n  Reports fitted values, multi-step forecast, MSE, R².\n\n  transformer(df, gdp, d_model=8, seqlen=12, lr=0.001, epochs=100)\n",
        "dr_learner" | "drlearner" => "dr_learner(y ~ treated, df, x=\"x1,x2\" [, folds=3])\n  DR-Learner (Kennedy 2023). Doubly-robust CATE via pseudo-\n  outcome regression. Cross-fitting for nuisance functions.\n  DR pseudo-outcome: AIPW-based. Reports ATE, CATE, CI,\n  propensity, outcome regression, CATE coefficients.\n\n  dr_learner(y ~ treatment, df, x=\"age,income\", folds=3)\n",
        "bart" | "bayesian_trees" => "bart(y ~ x1 + x2, df [, trees=20, depth=3, iter=100, burnin=20])\n  BART (Chipman-George-McCulloch 2010). Bayesian Additive\n  Regression Trees. Sum-of-trees with Bayesian shrinkage.\n  Gibbs sampling for sigma². Variable inclusion proportions.\n  Reports fitted values, posterior sigma², R², MSE.\n\n  bart(price ~ bedrooms + sqft, df, trees=20, depth=3, iter=100)\n",
        "gp" | "gaussian_process" => "gp(y ~ x1 + x2, df)\n  Gaussian Process Regression (Rasmussen-Williams 2006).\n  Squared Exponential (RBF) kernel. Grid search MLE for\n  hyperparameters (length scale, signal variance, noise).\n  Reports fitted values with uncertainty, log marginal lik.\n\n  gp(price ~ bedrooms + sqft, df)\n",
        "tmle" => "tmle(y ~ treated, df, w=\"c1,c2\")\n  TMLE (van der Laan-Rubin 2006). Targeted Maximum Likelihood\n  Estimation. Doubly-robust ATE via targeting step.\n  Initial Q(W) and g(W) via OLS. Clever covariate H.\n  Fluctuation epsilon. EIF-based SE. Reports ATE, SE, CI,\n  epsilon, initial ATE, propensity, Q*, EIF.\n\n  tmle(y ~ treatment, df, w=\"age,income\")\n",
        "orf" | "orthogonal_forest" => "orf(y ~ treated, df, x=\"x1,x2\", w=\"c1,c2\" [, trees=50, depth=5])\n  Orthogonal Random Forest (Oprescu-Syrgkanis-Wu 2019).\n  Doubly-robust CATE via orthogonalization + forest.\n  Residualize T and Y w.r.t. confounders W. Forest on\n  residualized signals. Reports ATE, CATE, CI, importance.\n\n  orf(y ~ treatment, df, x=\"age\", w=\"income,edu\", trees=50)\n",
        "spectral" | "spectral_clustering" => "spectral(df, x=\"x1,x2\", k=3 [, sigma=auto])\n  Spectral Clustering (Ng-Jordan-Weiss 2002). Clustering via\n  eigenstructure of similarity graph. Gaussian kernel affinity.\n  Normalized graph Laplacian. K smallest eigenvectors.\n  K-means in eigenspace. Reports labels, eigenvalues, inertia.\n\n  spectral(df, x=\"x1,x2\", k=3)\n",
        "isotonic" | "isotonic_reg" => "isotonic(y ~ x, df [, decreasing])\n  Isotonic Regression (Barlow et al. 1972). Monotone regression\n  via Pool Adjacent Violators Algorithm (PAVA). Non-decreasing\n  by default; use 'decreasing' for non-increasing. Reports\n  fitted values, step function, R², MSE.\n\n  isotonic(y ~ x, df)\n",
        "causal_impact" | "causalimpact" => "causal_impact(df, y_var, controls=\"c1,c2\", period=N)\n  Causal Impact (Brodersen-Gallus-Henderson-Orban 2015).\n  Bayesian structural time series for counterfactual prediction.\n  OLS on pre-treatment + local level state. Reports avg effect,\n  cumulative effect, CIs, P(effect>0), counterfactual path.\n\n  causal_impact(df, gdp, controls=\"gdp_us,gdp_uk\", period=50)\n",
        "mice_chained" | "mice_eq" => "mice_chained(df, vars=\"x1,x2,x3\" [, m=5, iter=10])\n  MICE (van Buuren-Groothuis-Oudshoorn 2011). Multiple imputation\n  by chained equations. Iterative regression imputation.\n  Rubin's rules for pooling. Reports imputed data, pooled mean,\n  variance, FMI.\n\n  mice_chained(df, vars=\"x1,x2,x3\", m=5, iter=10)\n",
        "kmeans" | "k_means" => "kmeans(df, x=\"x1,x2\", k=3)\n  K-Means Clustering (MacQueen 1967, Lloyd 1982). K-means++\n  initialization. Lloyd's algorithm. Reports labels, centroids,\n  inertia, between/total SS, % explained.\n\n  kmeans(df, x=\"x1,x2\", k=3)\n",
        "bayes_lm" | "bayesian_lm" => "bayes_lm(y ~ x1 + x2, df)\n  Bayesian Linear Regression with conjugate Normal-Inverse-Gamma\n  prior. Closed-form posterior. Weak default prior. Reports\n  posterior mean, SD, 95% credible intervals, P(coef>0),\n  sigma², log marginal likelihood, R².\n\n  bayes_lm(price ~ bedrooms + sqft, df)\n",
        "qqplot" => "qqplot(df, var)\n  Q-Q plot (ASCII).\n\n  qqplot(df, residuals)\n",
        "corrplot" => "corrplot(df, var1, var2 [, ...])\n  Correlation heatmap (ASCII).\n\n  corrplot(df, price, mpg, weight)\n",
        "adf" | "adtest" => "adf(df, var [, lags=auto])\n  Augmented Dickey-Fuller unit root test.\n\n  adf(df, gdp)\n",
        "kpss" => "kpss(df, var)\n  KPSS stationarity test.\n\n  kpss(df, gdp)\n",
        "pp" => "pp(df, var)\n  Phillips-Perron unit root test.\n\n  pp(df, gdp)\n",
        "ljungbox" | "lbtest" => "ljungbox(df, var [, lags=10])\n  Ljung-Box autocorrelation test.\n\n  ljungbox(df, returns, lags=10)\n",
        "archtest" | "engle_arch" => "archtest(df, var [, lags=5])\n  Engle's ARCH test for heteroskedasticity.\n\n  archtest(df, returns, lags=5)\n",
        "granger" => "granger(df, y, x [, lags=4])\n  Granger causality test.\n\n  granger(df, gdp, money_supply, lags=4)\n",
        "johansen" => "johansen(df, var1, var2 [, ...] [, lags=2])\n  Johansen cointegration test.\n\n  johansen(df, gdp, consumption, lags=2)\n",
        "bptest" | "bplm" => "bptest(df, formula, id=var)\n  Breusch-Pagan LM test for random effects.\n\n  bptest(df, Y ~ X1 + X2, id=firm)\n",
        "jb" | "jarque_bera" => "jb(df, var)\n  Jarque-Bera normality test.\n\n  jb(df, residuals)\n",
        "swilk" | "shapiro_wilk" | "shapiro" => "swilk(df, var)\n  Shapiro-Wilk test for normality (3 ≤ n ≤ 5000).\n\n  swilk(df, income)\n",
        "sfrancia" | "shapiro_francia" => "sfrancia(df, var)\n  Shapiro-Francia test for normality (5 ≤ n ≤ 5000).\n\n  sfrancia(df, income)\n",
        "sktest" => "sktest(df, var)\n  Skewness/Kurtosis tests for normality (Jarque-Bera + D'Agostino).\n\n  sktest(df, income)\n",
        "reset" => "reset(model)\n  Ramsey RESET specification test.\n\n  reset(m)\n",
        "durbinwatson" | "dw" => "dw(model)\n  Durbin-Watson test for first-order autocorrelation in OLS residuals.\n  DW ≈ 2: no autocorrelation; < 1.5: positive; > 2.5: negative.\n\n  dw(m)\n  durbinwatson(m)\n",
        "white" => "white(model)\n  White heteroskedasticity test.\n\n  white(m)\n",
        "portsort" | "portfolio_sort" => "portsort(df, ret, sortvar, n=5 [, time=var])\n  Portfolio sort analysis (quintile spreads).\n\n  portsort(df, ret, beta, n=5, time=month)\n",
        "doublesort" | "double_sort" => "doublesort(df, ret, var1, var2, n1=5, n2=5 [, time=var])\n  Double portfolio sort.\n\n  doublesort(df, ret, size, bm, n1=5, n2=5)\n",
        "let" => "let name = expr\n  Declare a mutable variable in the current scope.\n\n  let x = 10\n  let m = ols(Y ~ X, df)\n",
        "const" => "const name = expr\n  Declare an immutable variable. Cannot be reassigned or redeclared.\n\n  const PI = 3.14159\n  const N = 1000\n",
        "return" => "return [expr]\n  Exit current function and return a value (or Nil).\n  Only valid inside fn bodies.\n\n  fn add(a, b) { return a + b }\n  fn say_hi() { return }\n",
        "print" => "print(expr1 [, expr2, ...] [, sep=\" \"] [, end=\"\\n\"])\n  Print values with separator and line ending.\n\n  print(\"x =\", x, \"y =\", y)          // x = 3.14 y = 42\n  print(\"a\", \"b\", \"c\", sep=\", \")     // a, b, c\n  print(\"no newline\", end=\"\")         // no trailing newline\n  print()                             // empty line\n",
        "display" | "di" => "display expr\n  DEPRECATED. Use 'print' instead.\n  Still prints a scalar value (no parentheses, Stata-style), but will be removed.\n\n  print(mean(df, price))\n  print(x + y)\n  display mean(df, price)   // deprecated\n  display x + y             // deprecated\n",
        "scalar" => "scalar name = expr\n  Alias for 'let'.\n\n  scalar mu = mean(df, Y)\n",
        "input" => "input alias\ncol1 col2 col3\n1.0 2.0 3.0\nend\n  Create DataFrame from inline numeric data.\n\n  input df\n  Y X\n  4.0 1.0\n  5.0 2.0\n  end\n",
        "source" => "source(\"script.hay\")\n  Execute another Hayashi script (always re-runs).\n\n  source(\"utils.hay\")\n",
        "import" | "require" => "import(\"module_or_url\" [, as=alias_name, only=[\"func1\", ...]])\n  Load a module once (skips if already imported) and binds it to a namespace.\n  Search: ./ -> ~/.hay/plugins/ -> ~/.hay/packages/ -> plugin_path() dirs -> $HAY_PATH\n  URLs are downloaded automatically.\n\n  import(\"finance\")                          // namespace: finance\n  import(\"finance\", as=fin)                  // custom namespace: fin::func()\n  import(\"finance\", only=[\"sharpe\"])          // imports func directly to local scope\n  import(\"https://example.com/utils.hay\")     // remote\n  import(\"/path/to/mod\")                     // absolute\n",
        "install" => "install(\"user/repo\" [, version=\"v1.2.3\", force=true])\n  Download and install a Hayashi plugin from GitHub.\n  Native-only: requires network access and the 'native' feature.\n\n  install(\"sheep-farm/finance\")\n  install(\"sheep-farm/finance\", version=\"1.2.3\")\n  install(\"sheep-farm/finance\", force=true)   // overwrite if already installed\n\n  After installing, use import() to load the module.\n",
        "plugin_path" => "plugin_path(\"path1\", \"path2\", ...)\n  Register directories to search for plugins.\n  Call without arguments to list current paths.\n\n  plugin_path(\"/shared/plugins\", \"/team/lib\")\n  plugin_path()                // show registered paths\n  import(\"my_module\")          // now searches those dirs too\n",
        "plugin" | "plugins" => "Plugin system\n\n  1. Packages from GitHub (CLI or from inside a script):\n     hay install user/repo [version]    download .hay files or native dynamic library\n     install(\"user/repo\")               same, callable from a Hayashi script\n     hay remove  name                     uninstall\n     hay list                             show installed packages and versions\n\n     Version: use 'latest' or omit for latest release; '1.2.3' and 'v1.2.3' both work.\n\n  2. plugin_path(\"/dir\"): register search directories.\n\n  3. import(\"module\", as=alias): load once per session and assign custom namespace alias.\n     Search: ./ -> ~/.hay/plugins/ -> ~/.hay/packages/ -> plugin_path -> $HAY_PATH\n     URLs: import(\"https://...module.hay\")\n\n  4. source(\"script.hay\"): always re-execute without namespaces.\n\n  Usage after install:\n     import(\"repo_name/module\", as=my_alias)\n",
        "help" => "help()\nhelp(topic)\n  Show command index or detailed documentation for a topic.\n  Keywords can be quoted or passed bare: help(if), help(\"for\").\n\n  help()\n  help(ols)\n  help(\"if\")\n  help(about)\n  help(license)\n",
        "timer" | "bench" => "timer(expr)\n  Time an expression and print elapsed.\n\n  timer(ols(Y ~ X, df))\n",
        "set_seed" | "seed" => "set_seed(n)\n  Set RNG seed for reproducibility.\n\n  set_seed(42)\n",
        "preserve" => "preserve(df)\n  Save a snapshot of the DataFrame.\n\n  preserve(df)\n  // ... modify df ...\n  restore(df)\n",
        "restore" => "restore(df)\n  Restore DataFrame to last preserved state.\n\n  restore(df)\n",
        "for" => "for var in start..end { body }\nfor var in list { body }\n  Loop over range or list.\n\n  for i in 1..10 { display i }\n  for v in [\"X1\", \"X2\"] { eststo(ols(\"Y ~ \" + v, df)) }\n",
        "parallel" | "parallel_for" | "parallelfor" => concat!(
            "parallel for var in iter { body }\n",
            "parallel for var in iter, threads=N { body }\n",
            "  Concurrent variant of 'for'. Iterations run in parallel across\n",
            "  threads via std::thread::scope. Each iteration's return value\n",
            "  (last expression or explicit 'return') is collected into a list.\n\n",
            "  As an expression (preferred):\n",
            "    let results = parallel for t in tickers, threads=8 { ... }\n",
            "  As a statement (result stored in iteration variable):\n",
            "    parallel for t in tickers { ... }\n",
            "    // t now holds the list of results\n\n",
            "  Best practices:\n",
            "    1. Treat the body as a pure function: read outer variables,\n",
            "       do NOT reassign them. Mutations to outer variables inside\n",
            "       the body are silently discarded (each thread has its own\n",
            "       environment copy).\n",
            "    2. Return a value (last expression or 'return expr') from each\n",
            "       iteration. Use 'return nil' to skip an iteration.\n",
            "    3. Combine with rbind() to aggregate per-iteration DataFrames:\n",
            "       let results = parallel for i in 0..n, threads=8 { ... }\n",
            "       let all = rbind(results)\n",
            "    4. Model results (ols, iv, etc.) contain Rc and CANNOT be\n",
            "       captured from the outer scope. Compute models inside the\n",
            "       body instead.\n",
            "    5. threads=N defaults to available_parallelism(). Use a lower\n",
            "       value to limit CPU usage or when I/O is the bottleneck.\n",
        ),
        "while" => "while cond { body }\n  Loop while condition is true.\n\n  let i = 0\n  while i < 10 { i = i + 1 }\n",
        "fn" | "function" => "fn name(p1, p2, ...) { body }\n  Define a function. Parameters are const (immutable).\n  Use 'let' to create local mutable copies.\n\n  fn square(x) { return x * x }\n  fn add(a, b) {\n      let result = a + b\n      return result\n  }\n",
        "match" => "match expr {\n    pattern => result,\n    _ => default\n}\n  Pattern matching expression. Returns the matched arm's value.\n  Use _ as wildcard (matches anything).\n\n  let label = match x {\n      1 => \"one\",\n      2 => \"two\",\n      _ => \"other\"\n  }\n",
        "if" | "else" | "if_expr" | "ternary" => "if cond { then_expr } else { else_expr }\n  Conditional expression (returns a value). Requires else branch.\n\n  let label = if x > 0 { \"positive\" } else { \"negative\" }\n  let abs = if x < 0 { -x } else { x }\n",
        "in" => "expr in collection\n  Membership test. Works with list, dict (key check), and string (substring).\n\n  display 2 in [1, 2, 3]           // true\n  display \"name\" in {\"name\": \"A\"}  // true\n  display \"lo\" in \"hello\"          // true\n\n  if x in [1, 2, 3] { ... }\n",
        "try" | "catch" | "finally" | "try_catch" => "try { body } catch e { handler } [finally { cleanup }]\n  Execute body; if any error occurs, run handler with error in 'e'.\n  The optional finally block always runs, even after return/break/continue.\n\n  try {\n      load \"data.csv\" as df\n  } catch e {\n      display f\"Error: {e}\"\n  } finally {\n      quietly off\n  }\n",
        "pipe" | "|>" => "|> (pipe operator)\n  Pass left side as first argument to right side function.\n\n  [3, 1, 2] |> sort |> reverse\n  [1, 2, 3] |> map(|x| x * 10)\n  [1, 2, 3, 4] |> filter(|x| x > 2) |> push(5)\n",
        "closure" | "lambda" => "Closure: |params| expr\n  Anonymous function. Captures variables from outer scope.\n\n  let sq = |x| x * x\n  display sq(5)       // 25\n\n  map([1, 2, 3], |x| x * 2)       // [2, 4, 6]\n  filter([1, 2, 3], |x| x > 1)    // [2, 3]\n\n  let factor = 10\n  map([1, 2], |x| x * factor)      // [10, 20]\n",
        "fstring" | "f-string" | "interpolation" => "f\"text {expr} text {expr:fmt}\"\n  String interpolation with optional format specifiers.\n\n  let x = 3.14\n  display f\"pi = {x:.2f}\"        // pi = 3.14\n  display f\"sum = {2 + 3}\"       // sum = 5\n  display f\"{{literal braces}}\"  // {literal braces}\n\n  Format specifiers:\n    {x:.Nf}   N decimal places\n    {x:.Ne}   scientific notation\n",
        "int" => "int(x) -> int\n  Convert to integer (truncates floats).\n\n  display int(3.9)    // 3\n  display int(\"42\")  // 42\n  display int(true)   // 1\n",
        "float" => "float(x) -> float\n  Convert to float.\n\n  display float(42)     // 42\n  display float(\"3.14\") // 3.14\n",
        "str" | "string" => "str(x) -> string\n  Convert any value to string.\n\n  display str(3.14)  // \"3.14\"\n  display str(true)  // \"true\"\n",
        "bool" => "bool(x) -> bool\n  Convert to boolean. 0/nil/false -> false, anything else -> true.\n\n  display bool(0)    // false\n  display bool(42)   // true\n",
        "type" | "typeof" => "type(x) -> string\n  Get type name of a value.\n\n  display type(42)       // \"int\"\n  display type(3.14)     // \"float\"\n  display type([1, 2])   // \"list\"\n  display type({\"a\": 1}) // \"dict\"\n",
        "is_int" | "is_float" | "is_bool" | "is_str" | "is_string" | "is_nil" | "is_list" | "is_dict" | "is_df" | "is_dataframe" | "is_fn" | "is_function" => "is_int(x), is_float(x), is_bool(x), is_str(x), is_nil(x), is_list(x), is_dict(x), is_df(x), is_fn(x) -> bool\n  Type predicates.\n\n  display is_int(42)      // true\n  display is_str(\"hi\")  // true\n  display is_df(df)        // true\n",
        "push" => "push(list, item) -> new list\n  Append item to end.\n\n  let b = push([1, 2], 3)  // [1, 2, 3]\n",
        "pop" => "pop(list) -> new list\n  Remove last item.\n\n  let b = pop([1, 2, 3])  // [1, 2]\n",
        "insert" => "insert(list, index, item) -> new list\n  Insert at position.\n\n  let b = insert([1, 3], 1, 2)  // [1, 2, 3]\n",
        "remove" => "remove(list, index) -> new list\n  Remove item at position.\n\n  let b = remove([1, 2, 3], 1)  // [1, 3]\n",
        "clear" => "clear(list) -> new list\n  Return empty list.\n\n  let b = clear([1, 2, 3])  // []\n",
        "reverse" => "reverse(list) -> new list\n  Reverse order.\n\n  let b = reverse([1, 2, 3])  // [3, 2, 1]\n",
        "index" | "indexof" => "index(list, item) -> int\n  Find position of item (-1 if not found).\n\n  display index([10, 20, 30], 20)  // 1\n",
        "slice" => "slice(list, start [, end]) -> new list\n  Subsequence from start to end (exclusive).\n\n  let b = slice([10, 20, 30, 40], 1, 3)  // [20, 30]\n",
        "join" => "join(list [, separator]) -> string\n  Concatenate list elements.\n\n  display join([\"a\", \"b\", \"c\"], \"-\")  // a-b-c\n",
        "map" => "map(list, fn) -> new list\n  Apply function to each element.\n\n  fn dbl(x) { return x * 2 }\n  let b = map([1, 2, 3], dbl)  // [2, 4, 6]\n",
        "unique" => "unique(list) -> new list\n  Remove duplicates, preserving order.\n\n  let b = unique([1, 2, 2, 3])  // [1, 2, 3]\n",
        "flatten" => "flatten(list) -> new list\n  Flatten nested lists one level.\n\n  let b = flatten([[1, 2], [3]])  // [1, 2, 3]\n",
        "range" => "range(start, end [, step]) -> list\n  Generate integer sequence.\n\n  let r = range(0, 5)     // [0, 1, 2, 3, 4]\n  let r = range(0, 10, 2) // [0, 2, 4, 6, 8]\n",
        "len" => "len(x) -> int\n  Length of list, dict, or string.\n\n  display len([1, 2, 3])  // 3\n  display len(\"hello\")   // 5\n",
        "dict" => "Dict literal: {\"key\": value, ...}\n  Indexing: d[\"key\"]\n\n  let d = {\"name\": \"Alice\", \"age\": 30}\n  display d[\"name\"]\n\nOperations:\n  keys(d), values(d), has_key(d, \"k\")\n  dict_set(d, \"k\", v), dict_remove(d, \"k\")\n  dict_merge(d1, d2), len(d)\n",
        "keys" => "keys(dict) -> list\n  Sorted list of keys.\n\n  let k = keys({\"b\": 2, \"a\": 1})  // [\"a\", \"b\"]\n",
        "values" => "values(dict) -> list\n  List of values (sorted by key).\n\n  let v = values({\"a\": 10, \"b\": 20})\n",
        "has_key" => "has_key(dict, \"key\") -> bool\n  Check if key exists.\n\n  display has_key(d, \"name\")  // true\n",
        "dict_set" | "dset" => "dict_set(dict, \"key\", value) -> new dict\n  Add or update a key.\n\n  let d2 = dict_set(d, \"age\", 31)\n",
        "dict_remove" | "dremove" => "dict_remove(dict, \"key\") -> new dict\n  Remove a key.\n\n  let d2 = dict_remove(d, \"age\")\n",
        "dict_merge" | "dmerge" => "dict_merge(d1, d2) -> new dict\n  Merge two dicts. d2 values overwrite d1.\n\n  let d3 = dict_merge(d1, d2)\n",
        "upper" => "upper(s) -> string\n  Convert to uppercase.\n\n  display upper(\"hello\")  // HELLO\n",
        "lower" => "lower(s) -> string\n  Convert to lowercase.\n\n  display lower(\"HELLO\")  // hello\n",
        "trim" => "trim(s) -> string\n  Remove leading/trailing whitespace.\n\n  display trim(\"  hi  \")  // hi\n",
        "substr" => "substr(s, start [, length]) -> string\n  Substring extraction.\n\n  display substr(\"hello\", 1, 3)  // ell\n",
        "split" => "split(s, delimiter) -> list\n  Split string into list.\n\n  let parts = split(\"a,b,c\", \",\")  // [\"a\", \"b\", \"c\"]\n",
        "str_replace" => "str_replace(s, from, to) -> string\n  Replace all occurrences.\n\n  display str_replace(\"hello\", \"l\", \"r\")  // herro\n",
        "contains" => "contains(s, pattern) -> bool\n  Check if string contains substring.\n\n  display contains(\"hello\", \"ell\")  // true\n  display contains(\"hello\", \"xyz\")  // false\n",
        "regexm" => "regexm(s, pattern) -> bool\n  Regex match test.\n\n  display regexm(\"abc123\", \"[0-9]+\")  // true\n",
        "regexr" => "regexr(s, pattern, replacement) -> string\n  Replace first regex match.\n\n  display regexr(\"abc123\", \"[0-9]+\", \"NUM\")\n",
        "regexra" => "regexra(s, pattern, replacement) -> string\n  Replace all regex matches.\n\n  display regexra(\"a1b2c3\", \"[0-9]\", \"X\")\n",
        "regexs" => "regexs(s, pattern) -> string\n  Extract first capture group.\n\n  display regexs(\"price: 42.5\", \"([0-9.]+)\")  // 42.5\n",
        "lowess" => "lowess(df, yvar, xvar [, frac=0.5, it=3])\n  Local polynomial smoothing.\n\n  let m = lowess(df, y, x, frac=0.5)\n  predict df yhat = m, \"smoothed\"\n",
        "pca" => "pca(df, var1, var2 [, ...] [, ncomp=2])\n  Principal component analysis.\n\n  pca(df, x1, x2, x3, ncomp=2)\n",
        "factor" => "factor(df, var1, var2 [, ...] [, nfactors=2])\n  Factor analysis.\n\n  factor(df, q1, q2, q3, q4, nfactors=2)\n",
        "manova" => "manova(df, var1, var2 [, ...], by=\"group\")\n  Multivariate ANOVA.\n\n  manova(df, price, mpg, weight, by=\"foreign\")\n",
        "anova" => "anova(df, var, by=\"group\")\n  One-way ANOVA.\n\n  anova(df, price, by=\"foreign\")\n",
        "gmm" => concat!(
            "gmm(endog_formula, instrument_formula, df)\n\n",
            "  Linear GMM (Two-Step Efficient). Robust to heteroskedasticity.\n",
            "  Reports Hansen's J-statistic for overidentification test.\n\n",
            "  Same formula syntax as iv():\n",
            "    1st formula: y ~ all regressors (exog + endog)\n",
            "    2nd formula: ~ exog + excluded instruments\n\n",
            "  Example:\n",
            "    let m = gmm(y ~ x1 + x2, ~ x1 + z1 + z2 + z3, df)\n",
        ),
        "clogit" | "xtlogit_fe" => concat!(
            "clogit(formula, df, group=\"id_col\")\n",
            "  Alias: xtlogit_fe\n\n",
            "  Conditional (fixed-effects) logit for panel binary outcomes.\n",
            "  Groups without variation in y are dropped.\n\n",
            "  Example:\n",
            "    let m = clogit(y ~ x1 + x2, df, group=\"id\")\n",
        ),
        "cpoisson" | "xtpoisson_fe" | "ppml" => concat!(
            "cpoisson(formula, df, group=\"id_col\")\n",
            "  Aliases: xtpoisson_fe, ppml\n\n",
            "  Conditional (fixed-effects) Poisson. Consistent under\n",
            "  unobserved heterogeneity (PPML estimator).\n\n",
            "  Example:\n",
            "    let m = cpoisson(exports ~ gdp + dist, df, group=\"pair\")\n",
        ),
        "cmnlogit" | "cmlogit" | "conditional_mlogit" => concat!(
            "cmnlogit(formula, df, group=\"id_col\", alts=N)\n",
            "  Aliases: cmlogit, conditional_mlogit\n\n",
            "  Conditional multinomial logit (McFadden's choice model).\n",
            "  Data must be stacked: N_occasions * N_alternatives rows.\n\n",
            "  Options:\n",
            "    group=\"col\"   Choice-set/individual identifier\n",
            "    alts=N        Number of alternatives per choice set\n\n",
            "  Example:\n",
            "    let m = cmnlogit(choice ~ price + quality, df, group=\"id\", alts=3)\n",
        ),
        _ => return None,
    };
    Some(h)
}
